toolArgs.file_text:
.catalog-layout {
    display: flex;
    gap: 1.5rem;
}

.catalog-sidebar {
    flex: 0 0 25%;
    max-width: 25%;
    border-right: 1px solid #dee2e6;
    padding-right: 1.5rem;
}

.catalog-main {
    flex: 1;
    min-width: 0;
}

.filter-section {
    margin-bottom: 1.25rem;
}

.filter-section h6 {
    margin-bottom: 0.5rem;
    font-weight: 600;
}

.catalog-toolbar {
    display: flex;
    justify-content: space-between;
    align-items: center;
    margin-bottom: 1.25rem;
    padding: 0.75rem;
    background-color: #f8f9fa;
    border-radius: 0.375rem;
}

.product-grid {
    display: grid;
    grid-template-columns: repeat(auto-fill, minmax(240px, 1fr));
    gap: 1.25rem;
}

